#[napi]
pub fn register_ocr_backend(obj: napi::bindgen_prelude::Object) -> napi::Result<()> {
    let bridge = JsOcrBackendBridge::new(obj)?;
    let arc: Arc<dyn kreuzberg::plugins::OcrBackend> = Arc::new(bridge);
    let registry = kreuzberg::plugins::registry::get_ocr_backend_registry();
    let mut registry = registry.write();
    registry.register(arc).map_err(|e| {
        napi::Error::new(
            napi::Status::GenericFailure,
            format!("Failed to register backend: {}", e),
        )
    })
}

